// src/middleware/validate.ts
import { z } from "zod";
import type { Request, Response, NextFunction } from "express";

const MessageSchema = z.object({
  role: z.enum(["user", "assistant", "system"]),
  content: z.string().min(1).max(32_768),
});

export const ChatRequestSchema = z.object({
  messages: z.array(MessageSchema).min(1).max(50).refine(
    (msgs) => msgs[msgs.length - 1].role === "user",
    "Last message must have role 'user'"
  ),
  model: z.string().default("claude-sonnet-4-6"),
  maxTokens: z.number().int().min(1).max(8192).default(1024),
  temperature: z.number().min(0).max(1).default(0.7),
  stream: z.boolean().default(true),
});

export type ChatRequest = z.infer<typeof ChatRequestSchema>;

export function validateBody<T>(schema: z.ZodSchema<T>) {
  return (req: Request, res: Response, next: NextFunction) => {
    const result = schema.safeParse(req.body);
    if (!result.success) {
      return res.status(422).json({
        error: "Validation failed",
        details: result.error.flatten(),
      });
    }
    req.body = result.data;
    next();
  };
}

// src/routes/chat.ts
import { Router } from "express";
import { ChatRequestSchema, validateBody, type ChatRequest } from "../middleware/validate";
import { authMiddleware } from "../middleware/auth";
import { rateLimiter } from "../middleware/rateLimit";
import { streamLLM, completeLLM } from "../services/llm";

export const chatRouter = Router();

chatRouter.post(
  "/completions",
  authMiddleware,
  rateLimiter,
  validateBody(ChatRequestSchema),
  async (req, res) => {
    const body = req.body as ChatRequest;

    if (body.stream) {
      res.setHeader("Content-Type", "text/event-stream");
      res.setHeader("Cache-Control", "no-cache");
      res.setHeader("X-Accel-Buffering", "no");
      res.flushHeaders();

      try {
        for await (const chunk of streamLLM(body)) {
          res.write(\`data: \${JSON.stringify({ delta: chunk })}\n\n\`);
        }
        res.write("data: [DONE]\n\n");
      } catch (err) {
        res.write(\`data: \${JSON.stringify({ error: "Stream error" })}\n\n\`);
      } finally {
        res.end();
      }
    } else {
      const response = await completeLLM(body);
      res.json(response);
    }
  }
);

// src/services/llm.ts
import Anthropic from "@anthropic-ai/sdk";
import type { ChatRequest } from "../middleware/validate";
import { config } from "../config";

const client = new Anthropic({ apiKey: config.anthropicApiKey });

function buildMessages(req: ChatRequest) {
  const system = req.messages.find((m) => m.role === "system")?.content
    ?? "You are a helpful assistant.";
  const messages = req.messages
    .filter((m) => m.role !== "system")
    .map((m) => ({ role: m.role as "user" | "assistant", content: m.content }));
  return { system, messages };
}

export async function* streamLLM(req: ChatRequest): AsyncGenerator<string> {
  const { system, messages } = buildMessages(req);
  const stream = await client.messages.stream({
    model: req.model,
    max_tokens: req.maxTokens,
    temperature: req.temperature,
    system,
    messages,
  });
  for await (const event of stream) {
    if (
      event.type === "content_block_delta" &&
      event.delta.type === "text_delta"
    ) {
      yield event.delta.text;
    }
  }
}

export async function completeLLM(req: ChatRequest) {
  const { system, messages } = buildMessages(req);
  const response = await client.messages.create({
    model: req.model,
    max_tokens: req.maxTokens,
    temperature: req.temperature,
    system,
    messages,
  });
  return {
    id: response.id,
    content: (response.content[0] as Anthropic.TextBlock).text,
    model: response.model,
    usage: response.usage,
  };
}

// src/middleware/auth.ts
import type { Request, Response, NextFunction } from "express";
import jwt from "jsonwebtoken";
import { config } from "../config";

export interface AuthPayload {
  sub: string;
  email?: string;
}

declare global {
  namespace Express {
    interface Request {
      user?: AuthPayload;
    }
  }
}

export function authMiddleware(
  req: Request,
  res: Response,
  next: NextFunction
) {
  const header = req.headers.authorization;
  if (!header?.startsWith("Bearer ")) {
    return res.status(401).json({ error: "Missing token" });
  }
  const token = header.slice(7);
  try {
    req.user = jwt.verify(token, config.jwtSecret) as AuthPayload;
    next();
  } catch {
    res.status(401).json({ error: "Invalid or expired token" });
  }
}

// src/middleware/rateLimit.ts
import type { Request, Response, NextFunction } from "express";
import { createClient } from "redis";
import { config } from "../config";

const redis = createClient({ url: config.redisUrl });
redis.connect();

export async function rateLimiter(
  req: Request,
  res: Response,
  next: NextFunction
) {
  const userId = req.user?.sub ?? req.ip;
  const key = \`rate:\${userId}\`;

  const count = await redis.incr(key);
  if (count === 1) {
    await redis.expire(key, 60);  // 60-second window
  }
  if (count > config.requestsPerMinute) {
    return res.status(429).json({
      error: \`Rate limit: \${config.requestsPerMinute} req/min\`,
    });
  }
  res.setHeader("X-RateLimit-Remaining", config.requestsPerMinute - count);
  next();
}

// src/config.ts
import { z } from "zod";
import "dotenv/config";

const ConfigSchema = z.object({
  anthropicApiKey: z.string().min(1),
  jwtSecret: z.string().min(32),
  databaseUrl: z.string().url(),
  redisUrl: z.string().default("redis://localhost:6379"),
  port: z.coerce.number().default(3000),
  allowedOrigins: z.string().transform((s) => s.split(",")).default("http://localhost:5173"),
  requestsPerMinute: z.coerce.number().default(20),
});

export const config = ConfigSchema.parse({
  anthropicApiKey: process.env.ANTHROPIC_API_KEY,
  jwtSecret: process.env.JWT_SECRET,
  databaseUrl: process.env.DATABASE_URL,
  redisUrl: process.env.REDIS_URL,
  port: process.env.PORT,
  allowedOrigins: process.env.ALLOWED_ORIGINS,
  requestsPerMinute: process.env.REQUESTS_PER_MINUTE,
});

// src/routes/health.ts
import { Router } from "express";
import { createClient } from "redis";
import { config } from "../config";

export const healthRouter = Router();

healthRouter.get("/health", (_req, res) => {
  res.json({ status: "ok" });
});

healthRouter.get("/ready", async (_req, res) => {
  const checks: Record<string, string> = {};
  let ok = true;

  try {
    const redis = createClient({ url: config.redisUrl });
    await redis.connect();
    await redis.ping();
    await redis.disconnect();
    checks.redis = "ok";
  } catch (e) {
    checks.redis = String(e);
    ok = false;
  }

  checks.llmKey = config.anthropicApiKey ? "ok" : "missing";
  if (!config.anthropicApiKey) ok = false;

  res
    .status(ok ? 200 : 503)
    .json({ status: ok ? "ok" : "degraded", checks });
});

