import request from "supertest";
import { createApp } from "../app";
import * as llmService from "../services/llm";
import jwt from "jsonwebtoken";
import { config } from "../config";

jest.mock("../services/llm");
jest.mock("../middleware/rateLimit", () => ({
  rateLimiter: (_req: any, _res: any, next: any) => next(),
}));

const app = createApp();

function makeToken() {
  return jwt.sign({ sub: "user-123" }, config.jwtSecret);
}

test("POST /chat/completions streams SSE", async () => {
  async function* fakeStream() {
    for (const chunk of ["Hello", ", ", "world!"]) yield chunk;
  }
  jest.spyOn(llmService, "streamLLM").mockImplementation(() => fakeStream());

  const res = await request(app)
    .post("/chat/completions")
    .set("Authorization", \`Bearer \${makeToken()}\`)
    .send({ messages: [{ role: "user", content: "Hi" }] })
    .buffer(true)
    .parse((res, callback) => {
      let data = "";
      res.on("data", (chunk: Buffer) => (data += chunk.toString()));
      res.on("end", () => callback(null, data));
    });

  expect(res.status).toBe(200);
  expect(res.headers["content-type"]).toMatch(/text\/event-stream/);
  expect(res.body).toContain('"delta":"Hello"');
  expect(res.body).toContain("[DONE]");
});

test("POST /chat/completions returns 401 without token", async () => {
  const res = await request(app)
    .post("/chat/completions")
    .send({ messages: [{ role: "user", content: "Hi" }] });
  expect(res.status).toBe(401);
});

test("POST /chat/completions returns 422 for bad body", async () => {
  const res = await request(app)
    .post("/chat/completions")
    .set("Authorization", \`Bearer \${makeToken()}\`)
    .send({ messages: [] });   // empty array fails min(1)
  expect(res.status).toBe(422);
});
